#include <bits/stdc++.h>
using namespace std;

int main(){
    int m;
    set<int> s;
    set<int>::iterator t;
    scanf("%d",&m);
    while(m--){
        int tp,l;
        scanf("%d%d",&tp,&l);
        if(tp==1){
            int siz=s.size();
            s.insert(l);
            if(siz==s.size())
                puts("Already Exist");
        }else{
            if(s.empty())
                puts("Empty");
            else{
                t=lower_bound(s.begin(),s.end(),l);
                if(t==s.end()){
                    t--;
                    printf("%d\n",*t);
                    s.erase(t);
                }else if(*t==l){
                    printf("%d\n",*t);
                    s.erase(t);
                }else if(t==s.begin()){
                    printf("%d\n",*t);
                    s.erase(t);
                }else if(*t-l>=l-(*(--t))){
                    printf("%d\n",*t);
                    s.erase(t);
                }else{
                    t++;
                    printf("%d\n",*t);
                    s.erase(t);
                }
            }
        }
    }
    return 0;
}
